from abc import ABC, abstractmethod

class CCA(ABC):
    _STANDARD_FEES = 15

    def __init__(self, name: str):
        self._name = name

    @property
    def name(self) -> str:
        return self._name

    @abstractmethod
    def getFees(self) -> float:
        pass
```

```python
class InterestGroup(CCA):
    _MAJOR_BASED_FEES = {"HRM": 21, "ECE": 25}

    def __init__(self, name: str, major: str = None):
        super().__init__(name)
        self._major = major

    def getFees(self) -> float:
        if self._major in InterestGroup._MAJOR_BASED_FEES:
            return InterestGroup._MAJOR_BASED_FEES[self._major]
        return CCA._STANDARD_FEES

    def __str__(self) -> str:
        return f"{self._name}, monthly: ${self.getFees():.2f}"
```

