class Student:
    _MAX_CCA_FEES = 45

    def __init__(self, id: str, name: str):
        self._id = id
        self._name = name
        self._ccaRecord = []

    def getCcaFees(self) -> float:
        total = 0
        for cca in self._ccaRecord:
            total += cca.getFees()
        return total

    def addCca(self, cca: CCA):
        if self.getCcaFees() + cca.getFees() <= Student._MAX_CCA_FEES:
            self._ccaRecord.append(cca)
```

